const listMinerChannelDevices = `-- name: ListMinerChannelDevices :many
WITH miner_channel_devices AS (
    SELECT
        d.device_identifier AS device_identifier,
        COALESCE(
            NULLIF(d.custom_name, ''),
            NULLIF(TRIM(CONCAT_WS(' ', NULLIF(dd.manufacturer, ''), NULLIF(dd.model, ''))), ''),
            d.device_identifier
        )::text AS display_name,
        COALESCE(d.worker_name, '') AS worker_name,
        COALESCE(dd.manufacturer, '') AS manufacturer,
        COALESCE(dd.model, '') AS model,
        COALESCE(dd.ip_address, '') AS ip_address,
        COALESCE(dd.firmware_version, '') AS firmware_version,
        COALESCE(d.serial_number, '') AS serial_number,
        c.id, c.org_id, c.label, c.is_default, c.owner_user_id, c.owner_username, c.expires_at, c.desired_config_jsonb, c.state, c.purpose, c.source_actor_type, c.source_actor_id, c.idempotency_key, c.created_at, c.updated_at,
        CASE
            WHEN c.is_default THEN (
                SELECT COUNT(*)::bigint
                FROM device d_default
                LEFT JOIN miner_channel_membership cm_default
                    ON cm_default.org_id = d_default.org_id
                   AND cm_default.device_identifier = d_default.device_identifier
                WHERE d_default.org_id = c.org_id
                  AND d_default.deleted_at IS NULL
                  AND cm_default.miner_channel_id IS NULL
            )
            ELSE COALESCE(m.explicit_member_count, 0)::bigint
        END AS explicit_member_count
    FROM device d
    JOIN discovered_device dd
        ON dd.id = d.discovered_device_id
       AND dd.org_id = d.org_id
       AND dd.deleted_at IS NULL
    LEFT JOIN miner_channel_membership cm
        ON cm.org_id = d.org_id
       AND cm.device_identifier = d.device_identifier
    JOIN miner_channel default_c
        ON default_c.org_id = d.org_id
       AND default_c.is_default = TRUE
    JOIN miner_channel c
        ON c.id = COALESCE(cm.miner_channel_id, default_c.id)
    LEFT JOIN (
        SELECT miner_channel_id, COUNT(*) AS explicit_member_count
        FROM miner_channel_membership
        GROUP BY miner_channel_id
    ) m ON m.miner_channel_id = c.id
    WHERE d.org_id = $13
      AND d.deleted_at IS NULL
)
SELECT device_identifier, display_name, worker_name, manufacturer, model, ip_address, firmware_version, serial_number, id, org_id, label, is_default, owner_user_id, owner_username, expires_at, desired_config_jsonb, state, purpose, source_actor_type, source_actor_id, idempotency_key, created_at, updated_at, explicit_member_count
FROM miner_channel_devices
WHERE (
    cardinality($1::text[]) = 0
    OR ('available' = ANY($1::text[]) AND is_default = TRUE)
    OR ('reserved' = ANY($1::text[]) AND is_default = FALSE)
  )
  AND (
    cardinality($2::bigint[]) = 0
    OR id = ANY($2::bigint[])
  )
  AND (
    cardinality($3::bigint[]) = 0
    OR owner_user_id = ANY($3::bigint[])
    OR ($4::boolean AND owner_user_id IS NULL)
  )
  AND (
    cardinality($5::text[]) = 0
    OR LOWER(BTRIM(manufacturer)) = ANY(
        SELECT LOWER(BTRIM(value))
        FROM unnest($5::text[]) AS value
    )
  )
  AND (
    cardinality($6::text[]) = 0
    OR LOWER(BTRIM(model)) = ANY(
        SELECT LOWER(BTRIM(value))
        FROM unnest($6::text[]) AS value
    )
  )
  AND (
    NOT $7::boolean
    OR display_name ILIKE '%' || $8::text || '%'
    OR worker_name ILIKE '%' || $8::text || '%'
    OR manufacturer ILIKE '%' || $8::text || '%'
    OR model ILIKE '%' || $8::text || '%'
    OR ip_address ILIKE '%' || $8::text || '%'
    OR serial_number ILIKE '%' || $8::text || '%'
    OR device_identifier ILIKE '%' || $8::text || '%'
    OR label ILIKE '%' || $8::text || '%'
    OR COALESCE(owner_username, '') ILIKE '%' || $8::text || '%'
  )
  AND (
    NOT $9::boolean
    OR display_name > $10::text
    OR (display_name = $10::text AND device_identifier > $11::text)
  )
ORDER BY display_name ASC, device_identifier ASC
LIMIT $12::int
`

