const listMinerChannels = `-- name: ListMinerChannels :many
SELECT
    c.id, c.org_id, c.label, c.is_default, c.owner_user_id, c.owner_username, c.expires_at, c.desired_config_jsonb, c.state, c.purpose, c.source_actor_type, c.source_actor_id, c.idempotency_key, c.created_at, c.updated_at,
    CASE
        WHEN c.is_default THEN (
            SELECT COUNT(*)::bigint
            FROM device d_default
            LEFT JOIN miner_channel_membership cm_default
                ON cm_default.org_id = d_default.org_id
               AND cm_default.device_identifier = d_default.device_identifier
            WHERE d_default.org_id = c.org_id
              AND d_default.deleted_at IS NULL
              AND cm_default.miner_channel_id IS NULL
        )
        ELSE COALESCE(m.explicit_member_count, 0)::bigint
    END AS explicit_member_count
FROM miner_channel c
LEFT JOIN (
    SELECT miner_channel_id, COUNT(*) AS explicit_member_count
    FROM miner_channel_membership
    GROUP BY miner_channel_id
) m ON m.miner_channel_id = c.id
WHERE c.org_id = $1
  AND ($2::boolean OR c.state = 'active')
  AND (
    NOT $3::boolean
    OR c.label ILIKE '%' || $4::text || '%'
    OR c.purpose ILIKE '%' || $4::text || '%'
    OR COALESCE(c.owner_username, '') ILIKE '%' || $4::text || '%'
  )
  AND (
    NOT $5::boolean
    OR c.is_default < $6::boolean
    OR (
      c.is_default = $6::boolean
      AND (
        c.updated_at < $7::timestamptz
        OR (c.updated_at = $7::timestamptz AND c.id < $8::bigint)
      )
    )
  )
ORDER BY c.is_default DESC, c.updated_at DESC, c.id DESC
LIMIT $9::int
`

